		@Override
		public NativeProbe newProbe() {
			return new RetainedNativeProbe();
		}

		/**
		 * Operator-owned probe: one dataset read stamp for the probe's lifetime (instead of one per scan) and one
		 * retained LmdbRecordIterator that is re-aimed per probe key instead of re-created. The source-open check runs
		 * once per open(), the same granularity the batched wrapper already reduced it to.
		 */
		private final class RetainedNativeProbe implements NativeProbe {
			private long readStamp;
			private boolean stampHeld;
			private LmdbRecordIterator retained;
			private boolean closed;
			private final CsrProbeSupport csr = csrCache != null && csrEligible ? new CsrProbeSupport(txn, explicit)
					: null;

			@Override
			public RecordIterator open(long subj, long pred, long obj, long context) throws IOException {
				if (closed) {
					throw new SailException("Probe has been closed");
				}
				if (!stampHeld) {
					readStamp = acquireNativeSourceReadLock();
					stampHeld = true;
				}
				try {
					assertNativeSourceOpen();
					if (!hasStatementsInSource()) {
						return EmptyRecordIterator.INSTANCE;
					}
					if (csr != null) {
						RecordIterator served = csr.tryServe(subj, pred, obj, context);
						if (served != null) {
							return served;
						}
					}
					if (retained == null) {
						retained = tripleStore.getTriplesRetained(txn, subj, pred, obj, context, explicit);
					} else {
						tripleStore.resetTriples(retained, subj, pred, obj, context, explicit);
					}
					return retained;
				} catch (RuntimeException | Error | IOException e) {
					close();
					throw e;
				}
			}

			@Override
			public boolean adjacencyCacheBacked() {
				return csr != null && csr.servedFromCache();
			}

			@Override
			public long[] adjacencyCacheKeys() {
				return csr != null ? csr.servedKeys() : null;
			}

			@Override
			public NativeLmdbQuerySource.NativeAdjacency adjacency(long predicate, boolean bySubject)
					throws IOException {
				if (closed) {
					throw new SailException("Probe has been closed");
				}
				if (!stampHeld) {
					readStamp = acquireNativeSourceReadLock();
					stampHeld = true;
				}
				try {
					assertNativeSourceOpen();
					return csr != null && hasStatementsInSource() ? csr.adjacency(predicate, bySubject) : null;
				} catch (RuntimeException | Error failure) {
					close();
					throw failure;
				}
			}

			@Override
			public void close() {
				if (closed) {
					return;
				}
				closed = true;
				try {
					if (csr != null) {
						csr.flushPending();
					}
					if (retained != null) {
						retained.dispose();
					}
				} finally {
					retained = null;
					if (stampHeld) {
						stampHeld = false;
						nativeSourceLock.unlockRead(readStamp);
					}
				}
			}
		}

		@Override
		public long count(long subj, long pred, long obj, long context) throws IOException {
			long readStamp = acquireNativeSourceReadLock();
			try {
				assertNativeSourceOpen();
				if (!hasStatementsInSource()) {
					return 0;
				}
				if (csrCache != null && csrEligible) {
					long cached = csrCache.tryCount(subj, pred, obj, context, explicit);
					if (cached >= 0) {
						return cached;
					}
				}
				return tripleStore.countTriples(txn, subj, pred, obj, context, explicit);
			} finally {
				nativeSourceLock.unlockRead(readStamp);
			}
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) throws IOException {
			long readStamp = acquireNativeSourceReadLock();
			try {
				assertNativeSourceOpen();
				if (!hasStatementsInSource()) {
					return false;
				}
				if (csrCache != null && csrEligible) {
					int cached = csrCache.tryHas(subj, pred, obj, context, explicit);
					if (cached >= 0) {
						return cached == 1;
					}
				}
				return tripleStore.hasTriples(txn, subj, pred, obj, context, explicit);
			} finally {
				nativeSourceLock.unlockRead(readStamp);
			}
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			assertNativeSourceOpen();
			if (!hasStatementsInSource()) {
				return 0D;
			}
			try {
				return tripleStore.cardinality(subj, pred, obj, context);
			} catch (IOException | RuntimeException e) {
				return Double.POSITIVE_INFINITY;
			}
		}

