		@Override
		public NativeLmdbQuerySource.ParallelSource[] openParallelSources(int count) throws IOException {
			// A connection-local write transaction may contain statements that a fresh read-only sibling cannot see.
			// Keep evaluation on the owning sequential source until the write commits; this preserves read-your-writes.
			if (storeTxnStarted.get()) {
				return null;
			}
			long readStamp = acquireNativeSourceReadLock();
			try {
				assertNativeSourceOpen();
				TxnManager txnManager = tripleStore.getTxnManager();
				StampedLongAdderLockManager txnLockManager = txnManager.lockManager();
				long txnStamp;
				try {
					txnStamp = txnLockManager.readLock();
				} catch (InterruptedException e) {
					Thread.currentThread().interrupt();
					throw new IOException(e);
				}
				ParallelSnapshotLease lease = null;
				ParallelSnapshotSource[] pending = null;
				Throwable primaryFailure = null;
				try {
					lease = new ParallelSnapshotLease(txnLockManager, txnStamp);
					long expectedSnapshotId = mdb_txn_id(txn.get());
					pending = new ParallelSnapshotSource[count];
					// The lease keeps commits, reset, and map-resize renewals out until the final sibling closes.
					// Refuse instead of mixing a stale original dataset with newly opened worker transactions.
					for (int i = 0; i < count; i++) {
						Txn siblingTxn = txnManager.createReadTxnUntracked();
						boolean transferred = false;
						try {
							long siblingSnapshotId = mdb_txn_id(siblingTxn.get());
							if (siblingSnapshotId != expectedSnapshotId) {
								return null;
							}
							pending[i] = new ParallelSnapshotSource(siblingTxn, explicit, siblingSnapshotId, lease);
							transferred = true;
						} finally {
							if (!transferred) {
								siblingTxn.close();
							}
						}
					}
					ParallelSnapshotSource[] result = pending;
					pending = null;
					return result;
				} catch (IOException | RuntimeException | Error e) {
					primaryFailure = e;
					throw e;
				} finally {
					Throwable failure = primaryFailure;
					if (pending != null) {
						for (ParallelSnapshotSource source : pending) {
							if (source != null) {
								try {
									source.close();
								} catch (RuntimeException | Error closeFailure) {
									failure = addParallelSnapshotFailure(failure, closeFailure);
								}
							}
						}
					}
					try {
						if (lease != null) {
							lease.release();
						} else {
							txnLockManager.unlockRead(txnStamp);
						}
					} catch (RuntimeException | Error closeFailure) {
						failure = addParallelSnapshotFailure(failure, closeFailure);
					}
					if (primaryFailure == null) {
						throwParallelSnapshotFailure(failure);
					}
				}
			} finally {
				nativeSourceLock.unlockRead(readStamp);
			}
		}

		private Throwable addParallelSnapshotFailure(Throwable primary, Throwable secondary) {
			if (primary == null) {
				return secondary;
			}
			if (primary != secondary) {
				primary.addSuppressed(secondary);
			}
			return primary;
		}

		private void throwParallelSnapshotFailure(Throwable failure) {
			if (failure instanceof RuntimeException) {
				throw (RuntimeException) failure;
			}
			if (failure != null) {
				throw (Error) failure;
			}
		}

		private long acquireNativeSourceReadLock() throws IOException {
			try {
				return nativeSourceLock.readLock();
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				throw new IOException(e);
			}
		}

		private long acquireNativeSourceReadLockUnchecked() {
			try {
				return nativeSourceLock.readLock();
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				throw new SailException(e);
			}
		}

		private long acquireNativeSourceWriteLock() {
			try {
				return nativeSourceLock.writeLock();
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				throw new SailException(e);
			}
		}

		private void assertNativeSourceOpen() {
			if (closed) {
				throw new QueryInterruptedException("Query evaluation was interrupted");
			}
		}

		private final class NativeSourceReadLockedPrefixRunCursor implements LmdbPrefixRunCursor {
			private final LmdbPrefixRunCursor delegate;
			private final long readStamp;
			private boolean closed;

			private NativeSourceReadLockedPrefixRunCursor(LmdbPrefixRunCursor delegate, long readStamp) {
				this.delegate = delegate;
				this.readStamp = readStamp;
			}

			@Override
			public boolean next() throws IOException {
				if (closed) {
					return false;
				}
				try {
					assertNativeSourceOpen();
					boolean hasNext = delegate.next();
					if (!hasNext) {
						close();
					}
					return hasNext;
				} catch (RuntimeException | Error | IOException e) {
					close();
					throw e;
				}
			}

			@Override
			public boolean seekTo(long value) throws IOException {
				if (closed) {
					return false;
				}
				try {
					assertNativeSourceOpen();
					return delegate.seekTo(value);
				} catch (RuntimeException | Error | IOException e) {
					close();
					throw e;
				}
			}

			@Override
			public boolean seekTo(long[] prefixValues) throws IOException {
				if (closed) {
					return false;
				}
				try {
					assertNativeSourceOpen();
					return delegate.seekTo(prefixValues);
				} catch (RuntimeException | Error | IOException e) {
					close();
					throw e;
				}
			}

			@Override
			public void stopBefore(long[] prefixValues) {
				delegate.stopBefore(prefixValues);
			}

			@Override
			public long[] quad() {
				return delegate.quad();
			}

			@Override
			public long runRowCount() {
				return delegate.runRowCount();
			}

			@Override
			public long getSourceRowsScannedActual() {
				return delegate.getSourceRowsScannedActual();
			}

			@Override
			public long getSourceRowsMatchedActual() {
				return delegate.getSourceRowsMatchedActual();
			}

			@Override
			public long getSourceRowsFilteredActual() {
				return delegate.getSourceRowsFilteredActual();
			}

			@Override
			public String getIndexName() {
				return delegate.getIndexName();
			}

			@Override
			public void close() {
				if (closed) {
					return;
				}
				closed = true;
				try {
					delegate.close();
				} finally {
					nativeSourceLock.unlockRead(readStamp);
				}
			}
		}

		private final class NativeSourceReadLockedRecordIterator implements RecordIterator {
			/** Rows pulled per delegate fill(): one txn-lock cycle and one open-check per batch. */
			private static final int BATCH_ROWS = 64;
			/**
			 * Single-row pulls before switching to batched fills, so the ubiquitous 0-2 row index-nested-loop probes
			 * stay allocation-free and pay exactly the same cost as before; genuine scans amortize the per-row lock,
			 * version check and wrapper dispatch from the third row on.
			 */
			private static final int SINGLE_PULLS_BEFORE_BATCHING = 2;

			private final RecordIterator delegate;
			private final long readStamp;
			private boolean closed;
			private boolean seekForwardMode;
			private int singlePulls;
			private long[] batch;
			private long[] scratch;
			private int batchCount;
			private int batchPos;
			private boolean exhausted;

			private NativeSourceReadLockedRecordIterator(RecordIterator delegate, long readStamp) {
				this.delegate = delegate;
				this.readStamp = readStamp;
			}

			@Override
			public long[] next() {
				if (closed) {
					return null;
				}
				try {
					if (batch != null) {
						return nextFromBatch();
					}
					assertNativeSourceOpen();
					if (seekForwardMode || singlePulls < SINGLE_PULLS_BEFORE_BATCHING) {
						singlePulls++;
						long[] record = delegate.next();
						if (record == null) {
							close();
						}
						return record;
					}
					batch = new long[BATCH_ROWS * 4];
					scratch = new long[4];
					return nextFromBatch();
				} catch (RuntimeException | Error e) {
					close();
					throw e;
				}
			}

			private long[] nextFromBatch() {
				if (batchPos >= batchCount) {
					if (exhausted) {
						close();
						return null;
					}
					assertNativeSourceOpen();
					batchCount = delegate.fill(batch, BATCH_ROWS);
					batchPos = 0;
					if (batchCount < BATCH_ROWS) {
						exhausted = true;
					}
					if (batchCount == 0) {
						close();
						return null;
					}
				}
				int offset = batchPos * 4;
				batchPos++;
				scratch[0] = batch[offset];
				scratch[1] = batch[offset + 1];
				scratch[2] = batch[offset + 2];
				scratch[3] = batch[offset + 3];
				return scratch;
			}

			@Override
			public int fill(long[] buffer, int maxRows) {
				if (closed) {
					return 0;
				}
				try {
					assertNativeSourceOpen();
					int rows = delegate.fill(buffer, maxRows);
					if (rows < maxRows) {
						close();
					}
					return rows;
				} catch (RuntimeException | Error e) {
					close();
					throw e;
				}
			}

			@Override
			public boolean seekForward(long subj, long pred, long obj, long context) {
				if (closed) {
					return false;
				}
				try {
					assertNativeSourceOpen();
					// A seek-driven cursor must not prefetch beyond its current frontier key: fill() may exhaust and
					// close the delegate while later seek targets still exist only in this wrapper's buffer.
					if (batch == null) {
						seekForwardMode = true;
					}
					boolean sought = delegate.seekForward(subj, pred, obj, context);
					if (sought && batch != null) {
						// buffered rows precede the seek target: drop them so the next pull refills from there
						batchPos = batchCount;
					}
					return sought;
				} catch (RuntimeException | Error e) {
					close();
					throw e;
				}
			}

			@Override
			public String getIndexName() {
				return delegate.getIndexName();
			}

			@Override
			public void close() {
				if (!closed) {
					try {
						delegate.close();
					} finally {
						closed = true;
						nativeSourceLock.unlockRead(readStamp);
					}
				}
			}
		}

